import { SignIn } from "./pages/SignIn/SignIn";
import { SignUp } from "./pages/SignUp/SignUp";
import './pages/styles/MainStyles.css'

function App() {
  let component
  switch(window.location.pathname){
    case "/":
      component = <SignIn/>
      break
    case "/registr":
      component = <SignUp/>
      break
  }
  return (
    <>
    <header className="signinСontainerHeader"> </header>
    {component}
    </>
  );
}

export default App;
